    int x, y, dist;
};

bool operator<(const Pos &a, const Pos &b) {
    return a.dist > b.dist; // Min heap based on distance
}

priority_queue<Pos> pq;

void dijkstra() {
    while (!pq.empty()) {
        Pos t = pq.top();
        pq.pop();
        if (dis[t.x][t.y] < t.dist) continue;
        if (map[t.x][t.y] - '0' == current) {
