        for (i=0;i<w;i++)

            ones.m[i][i]=1;

        ones.n=w;

        for (i=0;i<n;i++)

            scanf("%lld%lld",&Pos[i].a,&Pos[i].b);

        sort(Pos,Pos+n,cmp);

        if ((w==0)&&(h==0)&&(n==0)) return 0;

        memset(x,0,sizeof x);

        x[0]=1;

        memset(A.m,0,sizeof A.m);

        A.n=w;

        A.m[0][0]=1;

        A.m[0][1]=1;

        for (i=1;i<w;i++){

            A.m[i][i]=1;

            A.m[i][i-1]=1;

            A.m[i][i+1]=1;

        }

        k=0;

        j=0;

        while (j<n){

            p=Pos[j].b-1;

            if (p==k){

                x[Pos[j].a-1]=0;

            }

            else{

                get_x(Pow(A,p-k));

                k=p;

                x[Pos[j].a-1]=0;

